"use strict";(self.webpackChunkjuntotechnologies_github_io=self.webpackChunkjuntotechnologies_github_io||[]).push([[849],{6164:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"teamSidebar":[{"type":"link","label":"Shaun Porwal","href":"/docs/team/team","docId":"team/porwals","unlisted":false}]},"docs":{"intro":{"id":"intro","title":"Tutorial Intro","description":"Let\'s discover Docusaurus in less than 5 minutes."},"team/porwals":{"id":"team/porwals","title":"Team","description":"Shaun Porwal, based in New York, is a Biomedical Data Scientist with a B.E. in Biomedical Engineering & Chinese from Rutgers University, and an M.S. in Biomedical Data Science from Mount Sinai. He currently serves as a Data Analyst and Research Biostatistician at Memorial Sloan Kettering Cancer Center. He brought clinical model evaluation to the Python community by writing the \'dcurves\' package based on Decision Curve Analysis, and routinely contributes to statistical sections in urological cancer publications. Shaun has extensive experience from roles at Sema4 and Rutgers University, developing algorithms for time-series gene expression and performing structural variant detection on large data sets. He\'s proficient in several programming languages, including Python & R, and is multilingual, speaking English, Hindi, Mandarin, Japanese, and Spanish. Outside of work, Shaun enjoys learning languages, traveling, and running.","sidebar":"teamSidebar"}}}}')}}]);